class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.width = this.container.clientWidth;
        this.height = this.container.clientHeight || 400;
        this.canvas.width = this.width * window.devicePixelRatio;
        this.canvas.height = this.height * window.devicePixelRatio;
        this.canvas.style.width = `${this.width}px`;
        this.canvas.style.height = `${this.height}px`;
        this.ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    }

    getSteps(inputs) {
        const z = inputs.x1 * inputs.w1 + inputs.x2 * inputs.w2 + inputs.bias;
        const activation = 1 / (1 + Math.exp(-z));
        const error = 0.5 * Math.pow(activation - inputs.target, 2);
        const dL_da = activation - inputs.target;
        const da_dz = activation * (1 - activation);
        const delta = dL_da * da_dz;
        const dw1 = delta * inputs.x1;
        const dw2 = delta * inputs.x2;
        const db = delta;

        return [
            {
                title: "Step 1: Feedforward - Weighted Sum",
                description: `Calculate the linear sum $z$ from inputs and weights:\n\n$z = (${inputs.x1} \\cdot ${inputs.w1}) + (${inputs.x2} \\cdot ${inputs.w2}) + (${inputs.bias}) = ${z.toFixed(4)}$`
            },
            {
                title: "Step 2: Feedforward - Activation",
                description: `Pass $z$ through the Sigmoid activation function to get predicted output $\\hat{y}$:\n\n$\\hat{y} = \\sigma(${z.toFixed(4)}) = \\frac{1}{1 + e^{-${z.toFixed(4)}}} = ${activation.toFixed(4)}$`
            },
            {
                title: "Step 3: Compute Loss",
                description: `Compare prediction $\\hat{y} = ${activation.toFixed(4)}$ to target $y = ${inputs.target}$.\n\n$Loss = \\frac{1}{2}(${activation.toFixed(4)} - ${inputs.target})^2 = ${error.toFixed(6)}$`
            },
            {
                title: "Step 4: Backpropagation - Gradients",
                description: `Using Chain Rule, calculate how the loss changes with respect to weights:\n\n$\\frac{\\partial L}{\\partial z} = (\\hat{y} - y) \\cdot \\sigma'(z) = ${delta.toFixed(4)}$\n\n$\\nabla w_1 = ${dw1.toFixed(4)}, \\nabla w_2 = ${dw2.toFixed(4)}, \\nabla b = ${db.toFixed(4)}$`
            },
            {
                title: "Step 5: Weight Update",
                description: `Update parameters using Learning Rate $\\eta = ${inputs.lr}$:\n\n$w_1 \\leftarrow ${inputs.w1} - (${inputs.lr} \\cdot ${dw1.toFixed(4)}) = ${(inputs.w1 - inputs.lr * dw1).toFixed(4)}$\n\n$w_2 \\leftarrow ${inputs.w2} - (${inputs.lr} \\cdot ${dw2.toFixed(4)}) = ${(inputs.w2 - inputs.lr * dw2).toFixed(4)}$`
            }
        ];
    }

    drawNode(x, y, label, value, color, isActive) {
        const ctx = this.ctx;
        ctx.beginPath();
        ctx.arc(x, y, 30, 0, Math.PI * 2);
        ctx.fillStyle = isActive ? color : '#e2e8f0';
        ctx.fill();
        ctx.strokeStyle = isActive ? '#1e293b' : '#94a3b8';
        ctx.lineWidth = 2;
        ctx.stroke();

        ctx.fillStyle = isActive ? 'white' : '#64748b';
        ctx.font = 'bold 14px Inter, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(label, x, y - 5);
        ctx.font = '12px Inter, sans-serif';
        ctx.fillText(value, x, y + 15);
    }

    drawConnection(x1, y1, x2, y2, label, isActive, color, weight) {
        const ctx = this.ctx;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.strokeStyle = isActive ? color : '#cbd5e1';
        ctx.lineWidth = isActive ? 4 : 2;
        ctx.stroke();

        // Label
        const midX = (x1 + x2) / 2;
        const midY = (x1 + x2) / 2;
        ctx.fillStyle = isActive ? '#1e293b' : '#94a3b8';
        ctx.font = 'italic 12px serif';
        ctx.fillText(label + ': ' + weight, midX, (y1 + y2) / 2 - 10);
    }

    render(inputs, stepIndex) {
        const ctx = this.ctx;
        ctx.clearRect(0, 0, this.width, this.height);

        const z = inputs.x1 * inputs.w1 + inputs.x2 * inputs.w2 + inputs.bias;
        const activation = 1 / (1 + Math.exp(-z));

        const colors = {
            input: '#3b82f6',
            neuron: '#8b5cf6',
            output: '#10b981',
            error: '#ef4444'
        };

        const nodeX1 = 100;
        const nodeX2 = 400;
        const nodeY1 = 100;
        const nodeY2 = 300;
        const neuronY = 200;

        // Draw Connections
        this.drawConnection(nodeX1, nodeY1, nodeX2, neuronY, 'w1', stepIndex === 0 || stepIndex === 3 || stepIndex === 4, colors.input, inputs.w1);
        this.drawConnection(nodeX1, nodeY2, nodeX2, neuronY, 'w2', stepIndex === 0 || stepIndex === 3 || stepIndex === 4, colors.input, inputs.w2);

        // Draw Input Nodes
        this.drawNode(nodeX1, nodeY1, 'x1', inputs.x1, colors.input, stepIndex >= 0);
        this.drawNode(nodeX1, nodeY2, 'x2', inputs.x2, colors.input, stepIndex >= 0);

        // Draw Perceptron Node
        this.drawNode(nodeX2, neuronY, 'Σ, σ', `z=${z.toFixed(2)}`, colors.neuron, stepIndex >= 1);

        // Draw Output
        ctx.beginPath();
        ctx.moveTo(nodeX2 + 30, neuronY);
        ctx.lineTo(nodeX2 + 100, neuronY);
        ctx.strokeStyle = stepIndex >= 2 ? colors.output : '#cbd5e1';
        ctx.stroke();

        ctx.fillStyle = stepIndex >= 2 ? colors.output : '#94a3b8';
        ctx.font = 'bold 16px Inter, sans-serif';
        ctx.fillText(`ŷ = ${activation.toFixed(3)}`, nodeX2 + 140, neuronY + 5);

        if (stepIndex >= 2) {
            ctx.fillStyle = colors.error;
            ctx.font = '12px Inter, sans-serif';
            ctx.fillText(`Target: ${inputs.target}`, nodeX2 + 140, neuronY + 25);
        }

        // Backprop Arrows
        if (stepIndex >= 3) {
            ctx.strokeStyle = colors.error;
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(nodeX2, neuronY + 40);
            ctx.lineTo(nodeX1 + 40, nodeY1 + 40);
            ctx.stroke();
            ctx.beginPath();
            ctx.moveTo(nodeX2, neuronY + 40);
            ctx.lineTo(nodeX1 + 40, nodeY2 - 40);
            ctx.stroke();
            ctx.setLineDash([]);
            ctx.fillStyle = colors.error;
            ctx.fillText("Update Δw", (nodeX1 + nodeX2) / 2, neuronY + 60);
        }
    }
}
